// Flatten DataForSEO results — robust string parsing for n8n sandbox

const input = $input.first().json;

// Support both:
// 1) top-level object
// 2) top-level array with first object
const root = Array.isArray(input) ? input[0] : input;

const items = root?.tasks?.[0]?.result?.[0]?.items || [];

// 🚨 THE FIX: Count the total items right here
const totalCount = items.length;

return items.map(item => {
  const rawUrl = typeof item.url === 'string' ? item.url : '';

  let host = '';
  let domain = '';
  let path = '/';
  let query = '';
  let fragment = '';
  let parse_status = 'ok';

  try {
    if (rawUrl) {
      // Remove protocol
      let clean = rawUrl.replace(/^https?:\/\//i, '');

      // Extract fragment
      const hashIndex = clean.indexOf('#');
      if (hashIndex > -1) {
        fragment = clean.substring(hashIndex + 1);
        clean = clean.substring(0, hashIndex);
      }

      // Extract query
      const queryIndex = clean.indexOf('?');
      if (queryIndex > -1) {
        query = clean.substring(queryIndex + 1);
        clean = clean.substring(0, queryIndex);
      }

      // Split host/path
      const slashIndex = clean.indexOf('/');
      if (slashIndex > -1) {
        host = clean.substring(0, slashIndex);
        path = clean.substring(slashIndex) || '/';
      } else {
        host = clean;
        path = '/';
      }

      // Normalize domain
      domain = host.replace(/^www\./i, '');
    } else {
      parse_status = 'empty-url';
    }
  } catch (e) {
    parse_status = 'parse-error';
    host = '';
    domain = '';
    path = '/';
  }

  return {
    json: {
      total_serp_results: totalCount, // 🚨 Passed along for the LLM
      rank: item.rank_absolute || 0,
      rank_group: item.rank_group || 0,
      page: item.page || 0,
      serp_type: item.type || '',
      title: item.title || '',
      description: item.description || '',
      full_url: rawUrl,
      host,
      domain,
      path,
      query,
      fragment,
      parse_status
    }
  };
});

// 1. Fetch the items from the DataForSEO intersection results
const items = $input.first().json.tasks[0].result[0].items;

// 2. Fetch the "Dashboard" settings from your env_ node
const env = $('Set Environment Variables').item.json;

// 3. Map and Inject: Attach context to every keyword
return items.map(item => {
  return {
    json: {
      keyword: item.keyword_data.keyword,
      search_volume: item.keyword_data.keyword_info.search_volume,
      intent: item.keyword_data.search_intent_info.main_intent,
      source: `Intersection: ${env.target1} vs ${env.target2}`,
      discovery_priority: item.keyword_data.keyword_info.search_volume > 1000 ? 'high' : 'medium',

      // Accessible env settings for downstream nodes (SERP & AI)
      market_location: env.Location,
      market_language: env.Language,
      market_language_code: env.language_code,
      // We pass this so the AI knows which industry it's auditing
      industry_context: env.industry_context || 'plastering, ceiling, and wall finishing'
    }
  };
});

