const allItems = $input.all();

const goggleId = $('Execute Postgres Query').first().json.goggle_id;

// 2. Harde stop als de ID mist (Geen fallback ID's meer!)
if (!goggleId) {
    throw new Error("FATAL: Geen Goggle ID gevonden. Controleer of 'Run SQL Query' een geldige ID uit de database heeft gehaald.");
}

return allItems.map(item => {
    const rule = item.json;

    // Normalisatie
    const domain = rule.domain ? String(rule.domain).toLowerCase().trim() : 'geen-domein';
    const actionStr = rule.action ? String(rule.action).toLowerCase().trim() : 'discard';
    const finalAction = ['boost', 'downrank', 'discard'].includes(actionStr) ? actionStr : 'discard';
    const allowedTypes = ['specialist', 'retailer', 'aggregator'];
    const finalType = allowedTypes.includes(rule.site_type) ? rule.site_type : 'aggregator';

    return {
        json: {
            goggle_id: goggleId,  // 100% dynamisch
            target: domain,
            action: finalAction,
            strength: parseInt(rule.strength) || 1,
            target_type: 'site',
            path_pattern: '',
            confidence: 'low',
            site_type: finalType,
            reasoning: rule.reasoning || 'SERP Quick Scan',
            source: 'serp_audit'
        }
    };
});

const items = $input.all();

// 1. Safety Guard: If no new domains are found, stop the workflow here to save credits.
if (items.length === 0) return [];

// 2. Fetch goggle_id from the incoming data stream (SQL Merge passed it here)
const goggleId = items[0].json.goggle_id;

// 3. Strip tokens: Only keep domain and title (the context)
const optimizedList = items.map(item => {
  return {
    domain: item.json.domain,
    context: item.json.title
  };
});

// 4. Create the Master AI Task
return [{
  json: {
    goggle_id: goggleId, // Passed through for the final SORT node
    item_count: optimizedList.length,
    domain_list_string: JSON.stringify(optimizedList, null, 2)
  }
}];

// 1. Specifically look back at the Information Extractor node, ignoring the SQL output
const aiOutput = $('Information Extraction Agent').first().json.output.rules || [];

// 2. The rest of your logic remains the same
const expectedCount = $('Optimize AI Prompts').first().json.item_count;
let currentRetries = $input.first().json.retry_count || 0;

const isComplete = (aiOutput.length === expectedCount) || (currentRetries >= 3);

return [{
    json: {
        rules: aiOutput,
        is_complete: isComplete,
        retry_count: currentRetries + 1,
        actual_count: aiOutput.length,
        expected_count: expectedCount
    }
}];

const items = $input.all();

// Safety check for empty data
if (!items || items.length === 0) {
  return [{ json: { domain: 'unknown', error: 'No data' } }];
}

// Helper function (buiten de loop gehouden voor snelheid)
const parseUrlManual = (urlStr) => {
  try {
    let clean = String(urlStr || '');
    if (clean.startsWith('http://')) clean = clean.substring(7);
    if (clean.startsWith('https://')) clean = clean.substring(8);
    if (clean.startsWith('www.')) clean = clean.substring(4);
    let parts = clean.split('/');
    let hostname = parts[0] || 'unknown';
    let pathname = '/' + parts.slice(1).join('/').split('?')[0].split('#')[0];
    if (pathname.length > 1 && pathname.endsWith('/')) pathname = pathname.slice(0, -1);
    if (!pathname) pathname = '/';
    return { hostname, pathname, original: urlStr };
  } catch (e) { 
    return { hostname: 'error', pathname: '/', original: urlStr }; 
  }
};

const VAKKENNIS_KWS = ['expertise', 'trainingen', 'technisch', 'bestek', 'richtlijn', 'instructie', 'kennis', 'bim', 'stappenplan', 'projecten'];
const RETAIL_KWS = ['/product/', '/product-categorie/', '/shop/', '/merk/', 'winkelwagen', 'checkout', 'cart', 'bestellen'];

// 🚨 BATCH LOOP START: Verwerk ELK item in de batch apart
return items.map((item) => {
  const mapData = item.json;
  const urlsToProcess = mapData.links || [];
  const totalScanned = urlsToProcess.length;

  // 🚨 ROCKSOLID FIX: Haal goggle_id direct uit de input stroom of gebruik fallback. Geen storingsgevoelige $('Node') references meer!
  const goggleId = mapData.goggle_id || "a7b8c9d0-1234-4567-89ab-cdef01234567";

  const rawDomain = urlsToProcess[0]?.url || mapData.url || mapData.target || '';
  const domain = parseUrlManual(rawDomain).hostname;

  let pathCounts = {};
  let retailHits = 0;
  let cleanUrlsLog = [];

  urlsToProcess.forEach(urlItem => {
    const urlString = typeof urlItem === 'object' ? urlItem.url : urlItem;
    if (!urlString) return;

    const parsed = parseUrlManual(urlString);
    const pathLower = parsed.pathname.toLowerCase();

    const isJunk = pathLower.includes('sitemap') || pathLower.includes('.xml') || pathLower.includes('/tag/');
    if (isJunk) return;

    if (cleanUrlsLog.length < 100) cleanUrlsLog.push(parsed.original);

    if (RETAIL_KWS.some(kw => pathLower.includes(kw))) retailHits++;

    const segments = parsed.pathname.split('/').filter(s => s.length > 0);
    let currentPath = '';

    for (let i = 0; i < Math.min(segments.length, 3); i++) {
      currentPath += '/' + segments[i];
      if (!pathCounts[currentPath]) {
          pathCounts[currentPath] = { count: 0, vakkennisHits: 0, samples: [] };
      }
      pathCounts[currentPath].count++;

      VAKKENNIS_KWS.forEach(kw => {
          if (pathLower.includes(kw)) pathCounts[currentPath].vakkennisHits++;
      });

      if (pathCounts[currentPath].samples.length < 3) {
          pathCounts[currentPath].samples.push(parsed.original);
      }
    }
  });

  // Calculate ratios safely (prevent NaN if totalScanned is 0)
  const retailRatio = totalScanned > 0 ? (retailHits / totalScanned) : 0;
  const isRetailer = retailRatio > 0.2 || retailHits > 20;

  let powerFolders = Object.entries(pathCounts)
    .map(([path, data]) => {
        const isExpertise = data.vakkennisHits > 0 && (data.vakkennisHits / data.count >= 0.1);
        return { path, count: data.count, isExpertise, examples: data.samples };
    })
    .filter(f => f.count >= 3)
    .sort((a, b) => b.count - a.count);

  const finalFolders = powerFolders.filter((folder, index, self) => {
      const isRetailFolder = RETAIL_KWS.some(kw => folder.path.toLowerCase().includes(kw));
      const isRoot = folder.count > (totalScanned * 0.9) && folder.path.split('/').length <= 2 && !folder.isExpertise && !isRetailFolder;

      const hasSpecificChild = self.some(other => 
          other.path !== folder.path && other.path.startsWith(folder.path + '/') && other.count >= (folder.count * 0.8)
      );
      return !isRoot && !hasSpecificChild;
  }).slice(0, 15);

  const retailRatioPercent = Math.round(retailRatio * 100);

  // auditText wordt nu netjes IN de loop gedeclareerd en toegewezen
  const auditText = [
      `## DOMAIN AUDIT REQUEST: ${domain}`,
      `Totaal URLs gescand: ${totalScanned}`,
      `Retail/Product URL ratio: ${retailRatioPercent}%`,
      `Harde Retailer Indicatie: ${isRetailer ? 'JA (Grote catalogus/shop gevonden)' : 'NEE'}`,
      ``,
      `### Power Folders (Inhoudsanalyse):`,
      ...finalFolders.map(f => `- ${f.path} (${f.count} pagina's) ${f.isExpertise ? '[VAKKENNIS GEDETECTEERD]' : ''}\n  Voorbeelden: ${f.examples.join(' | ')}`)
  ].join('\n');

  // Stuur het resultaat voor dit specifieke domein terug
  return { 
      json: { 
          domain, 
          goggle_id: goggleId, 
          audit_text: auditText, 
          debug_log: { 
              scanned_total: totalScanned, 
              retail_hits: retailHits, 
              is_retailer: isRetailer, 
              power_folders: finalFolders 
          } 
      } 
  };
});

// Pak ALLE items die van de AI-node komen
const allItems = $input.all();

return allItems.map((item, index) => {
    const ai = item.json.output || {};

    // 🚨 FIX: We gebruiken hier de EXACTE naam van de node in je workflow
 const upstream = $items('Parse Domain Structures')[index].json;


    return {
        json: {
            // We zorgen dat er altijd een ID is, anders pakt hij de default
            goggle_id: upstream.goggle_id || "a7b8c9d0-1234-4567-89ab-cdef01234567",
            action: ai.action || 'boost',
            strength: parseInt(ai.strength) || 3,
            target: upstream.domain, 
            target_type: 'site',
            path_pattern: '',
            confidence: 'high',
            site_type: ai.site_type || 'unknown',
            reasoning: ai.reasoning || '',
            source: 'deep_audit'
        }
    };
});

