const items = $input.all();

return items.map(item => {
  const errorObj = item.json;

  // 1. DYNAMIC DATA RETRIEVAL
  // We look for the data in the current item (if passed through)
  // or via the pairedItem (the data from 'Process Domains in Batches')
  const goggleId = item.json.goggle_id || item.pairedItem?.json?.goggle_id;
  const targetUrl = item.json.target || item.json.url || item.pairedItem?.json?.target || "unknown-url";

  // 2. CLEAN DOMAIN EXTRACTION
  const domain = targetUrl
    .replace('https://', '')
    .replace('http://', '')
    .split('/')[0];

  return {
    json: {
      // 3. NO HARDCODED UUIDs
      goggle_id: goggleId,
      target: domain,
      site_type: 'error_timeout', 
      full_log: { 
        error: true, 
        message: errorObj.message || "Execution Error", 
        details: errorObj.errorDetails || errorObj || "No further details"
      }
    }
  };
});

